# setup-pwa-gestao-projetos-v6.ps1
# Correção agressiva do ícone: sobrescreve também vite.svg e todos os favicons possíveis.
# Marcador: GESTAO_PROJETOS_PWA_V6

$ErrorActionPreference = "Stop"

Write-Host "Aplicando PWA V6 - corrigindo fallback do icone..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path ".\public\icons" | Out-Null

# Remove vercel.json para não quebrar deploy
Remove-Item ".\vercel.json" -Force -ErrorAction SilentlyContinue

$svg = @'
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512">
  <rect width="512" height="512" rx="110" fill="#f6efe4"/>
  <rect x="42" y="42" width="428" height="428" rx="118" fill="#2d1d17"/>
  <rect x="330" y="82" width="94" height="94" rx="32" fill="#be7254"/>
  <text x="256" y="286" text-anchor="middle" font-family="Georgia,serif" font-size="156" font-weight="700" fill="#fff8ee">AD</text>
  <text x="256" y="362" text-anchor="middle" font-family="Arial,sans-serif" font-size="32" font-weight="800" letter-spacing="3" fill="#dcc3b3">PROJETOS</text>
</svg>

'@

# O ponto-chave: se o Chrome ainda tentar usar o ícone antigo do Vite, ele agora também vira AD.
$svg | Set-Content -Path ".\public\vite.svg" -Encoding UTF8
$svg | Set-Content -Path ".\public\favicon.svg" -Encoding UTF8
$svg | Set-Content -Path ".\public\icons\ad-projetos-v6.svg" -Encoding UTF8

$icons = @{
  "48" = @"

"@
  "72" = @"

"@
  "96" = @"

"@
  "128" = @"

"@
  "144" = @"

"@
  "152" = @"

"@
  "180" = @"

"@
  "192" = @"

"@
  "256" = @"

"@
  "384" = @"

"@
  "512" = @"

"@
}

foreach ($size in $icons.Keys) {
  [System.Convert]::FromBase64String($icons[$size]) | Set-Content -Path ".\public\icons\ad-projetos-$size-v6.png" -Encoding Byte
}

[System.Convert]::FromBase64String($icons["180"]) | Set-Content -Path ".\public\apple-touch-icon.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["192"]) | Set-Content -Path ".\public\favicon.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["192"]) | Set-Content -Path ".\public\logo192.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["512"]) | Set-Content -Path ".\public\logo512.png" -Encoding Byte

$faviconIco = @"

"@
[System.Convert]::FromBase64String($faviconIco) | Set-Content -Path ".\public\favicon.ico" -Encoding Byte

@'
{
  "id": "/ad-projetos-v6",
  "name": "Alexandre Dias | Gestão de Projetos",
  "short_name": "AD Projetos",
  "description": "Sistema premium para gestão de projetos de interiores.",
  "start_url": "/?pwa=ad-projetos-v6",
  "scope": "/",
  "display": "standalone",
  "orientation": "portrait-primary",
  "background_color": "#f6efe4",
  "theme_color": "#2d1d17",
  "lang": "pt-BR",
  "categories": ["business", "productivity"],
  "icons": [
    { "src": "/icons/ad-projetos-192-v6.png", "sizes": "192x192", "type": "image/png", "purpose": "any" },
    { "src": "/icons/ad-projetos-512-v6.png", "sizes": "512x512", "type": "image/png", "purpose": "any" },
    { "src": "/icons/ad-projetos-192-v6.png", "sizes": "192x192", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/ad-projetos-512-v6.png", "sizes": "512x512", "type": "image/png", "purpose": "maskable" }
  ]
}
'@ | Set-Content -Path ".\public\manifest.webmanifest" -Encoding UTF8
Copy-Item ".\public\manifest.webmanifest" ".\public\manifest.json" -Force

@'
// GESTAO_PROJETOS_PWA_V6
const CACHE_NAME = "ad-projetos-pwa-v6";

self.addEventListener("install", () => self.skipWaiting());

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(keys.map((key) => caches.delete(key))))
      .then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") return;
  event.respondWith(fetch(event.request).catch(() => caches.match(event.request)));
});
'@ | Set-Content -Path ".\public\sw.js" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V6
if ("serviceWorker" in navigator) {
  window.addEventListener("load", async () => {
    try {
      const registrations = await navigator.serviceWorker.getRegistrations();
      await Promise.all(registrations.map((registration) => registration.unregister()));
      await navigator.serviceWorker.register("/sw.js?v=6");
    } catch (error) {
      console.warn("Service Worker não registrado:", error);
    }
  });
}
'@ | Set-Content -Path ".\src\pwa-register.js" -Encoding UTF8

@'
<!doctype html>
<html lang="pt-BR">
  <head>
    <!-- GESTAO_PROJETOS_PWA_V6 -->
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover" />
    <title>Alexandre Dias | Gestão de Projetos</title>

    <link rel="manifest" href="/manifest.webmanifest?v=6" />
    <link rel="icon" href="/favicon.ico?v=6" sizes="any" />
    <link rel="icon" type="image/png" href="/favicon.png?v=6" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg?v=6" />
    <link rel="apple-touch-icon" href="/apple-touch-icon.png?v=6" />

    <meta name="theme-color" content="#2d1d17" />
    <meta name="mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-title" content="AD Projetos" />
    <meta name="application-name" content="AD Projetos" />
    <meta name="description" content="Sistema premium para gestão de projetos de interiores." />
  </head>
  <body>
    <div id="root"></div>
    <script type="module" src="/src/main.jsx"></script>
  </body>
</html>
'@ | Set-Content -Path ".\index.html" -Encoding UTF8

$mainPath = ".\src\main.jsx"
$main = Get-Content $mainPath -Raw
if ($main -notmatch 'pwa-register') {
  $main = 'import "./pwa-register";' + "`n" + $main
  Set-Content -Path $mainPath -Value $main -Encoding UTF8
}

Write-Host ""
Write-Host "PWA V6 aplicado." -ForegroundColor Green
Write-Host "Depois do deploy, teste /vite.svg, /favicon.svg e /manifest.webmanifest." -ForegroundColor Yellow
